mapper.select:
SELECT plan_item.id_ as act_id_, plan_item.id_ as act_name_, plan_item.case_inst_id_ as scope_id_, 'cmmn' as scope_type_, case_inst.case_def_id_ as scope_def_id_, def.key_ as scope_def_key_ FROM ${prefix}ACT_CMMN_RU_PLAN_ITEM_INST as plan_item JOIN ${prefix}ACT_CMMN_RU_CASE_INST as case_inst ON plan_item.case_inst_id_ = case_inst.id_ JOIN ${prefix}ACT_CMMN_CASEDEF as def ON case_inst.case_def_id_ = def.id_
LEFT JOIN ${prefix}ACT_CMMN_DEPLOYMENT as dep ON def.deployment_id_ = dep.id_
AND def.key_ = #{caseDefinitionKey}
AND case_inst.start_time_ >= #{startedAfter}
AND def.deployment_id_ IN ( SELECT id_ FROM ${prefix}ACT_CMMN_DEPLOYMENT ORDER BY deploy_time_ DESC LIMIT #{latestDeployments} )
ORDER BY plan_item.create_time_ DESC
